module RefModule (
    input D,
    input CLK,
    output reg Q,
    output reg Qn
);
    reg master_Q, master_Qn;

    // Master latch
      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge CLK or posedge dbg_halt) begin
        master_Q <= D;
        master_Qn <= ~D;
    end

    // Slave latch
    always @(negedge CLK) begin
        Q <= master_Q;
        Qn <= master_Qn;
    end
endmodule
